export const UpdateSessionParams = zod.object({
  id: zod.coerce.number(),
});

export const UpdateSessionBody = zod.object({
  name: zod.string().optional(),
  phaseFocus: zod.string().optional(),
  status: zod.enum(["pending", "round1", "round2", "complete"]).optional(),
});

export const UpdateSessionResponse = zod.object({
  id: zod.number(),
  name: zod.string(),
  scenarioId: zod.number().optional(),
  domainId: zod.number().optional(),
  status: zod.enum(["pending", "round1", "round2", "complete"]),
  phaseFocus: zod.string().optional(),
  agentCount: zod.number().optional(),
  createdAt: zod.string().optional(),
  updatedAt: zod.string().optional(),
});

